# OEIS sequence: A238385

# uses sign pattern (-1)^(n - k).
from math import prod
def T(n: int, k: int) -> int:
    if k > n: return 0
    if n == k: return 1
    m = n - k
    falling = prod(range(k + 1, n + 1))
    return (-1)**m * (falling // m)
for n in range(10):
    R = [T(n, k) for k in range(n+1)]; print(R)
